    private final String name;
    private final String banglaName;
    private final String description;

    InstitutionType(String name, String banglaName, String description) {
        this.name = name;
        this.banglaName = banglaName;
        this.description = description;
    }

    public String getName() {
        return name;
    }
    public String getBanglaName() {
        return banglaName;
    }
    public String getDescription() {
        return description;
    }

    public InstitutionTypeResponse toResponse() {
        return new InstitutionTypeResponse(
                this.name(),
                banglaName,
                name,
                description
        );
    }
